// src/components/admin/AddZapatilla.js
import React, { useState } from "react";
import { Link } from "react-router-dom";
import '../../styles.css';

export default function AddZapatilla() {
  const [nombre, setNombre] = useState("");
  const [marca, setMarca] = useState("");
  const [precio, setPrecio] = useState(0);
  const [cantidad, setCantidad] = useState(0);
  const [talle, setTalle] = useState("");
  const [categoria, setCategoria] = useState("");
  const [descripcion, setDescripcion] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    const nuevaZapatilla = {
      nombre,
      marca,
      precio,
      cantidad,
      talle,
      categoria,
      descripcion,
    };

    try {
      const res = await fetch("http://localhost:8080/zapatillas", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(nuevaZapatilla),
      });

      if (res.ok) {
        alert("Zapatilla guardada con éxito");
        setNombre("");
        setMarca("");
        setPrecio(0);
        setCantidad(0);
        setTalle("");
        setCategoria("");
        setDescripcion("");
      } else {
        alert("Error al guardar zapatilla");
      }
    } catch (error) {
      console.error("Error:", error);
      alert("Error de red al guardar zapatilla");
    }
  };

  return (
    <div className="form-container">
      <h2 className="title">Agregar nueva zapatilla</h2>
      <form onSubmit={handleSubmit} className="form">
        {/* El formulario de agregar zapatilla sigue igual */}
      </form>

      {/* Redirigir a la página de ver todas las zapatillas */}
      <Link to="/zapatillas" className="view-all-button">
        Ver todas las zapatillas
      </Link>
    </div>
  );
}
